import{_ as a,o as s,c as e,a2 as l}from"./chunks/framework.BflysNKA.js";const k=JSON.parse('{"title":"模型列表","description":"","frontmatter":{},"headers":[],"relativePath":"api/models.md","filePath":"api/models.md","lastUpdated":1778577020000}'),t={name:"api/models.md"};function n(d,i,p,r,h,o){return s(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="模型列表" tabindex="-1">模型列表 <a class="header-anchor" href="#模型列表" aria-label="Permalink to &quot;模型列表&quot;">​</a></h1><p>控制台的模型广场可以直接查看当前可用模型和价格：<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">https://xiaolan1.cn/pricing</a></p><p>如果你只想在脚本里先拉一遍可用模型，也可以直接请求接口。</p><p>第一次接入时，很多人会把“模型广场”和“模型列表接口”当成同一件事。可以简单这样理解：</p><ul><li><strong>模型广场</strong>：更适合人看，确认模型名、价格、分组、可用状态</li><li><strong>模型列表接口</strong>：更适合程序看，确认当前这把 Key 实际能拿到哪些 <code>id</code></li></ul><p>第一次接入时，先看模型广场，再看模型接口，通常最省时间：</p><ol><li>在模型广场确认目标模型确实存在</li><li>复制完整模型名</li><li>再用 <code>/v1/models</code> 看当前这把 Key 实际能不能看到它</li></ol><p>这样做能把“模型本来就没有”和“当前这把 Key 没权限看到”分开。</p><h2 id="列出模型-get" tabindex="-1">列出模型 GET <a class="header-anchor" href="#列出模型-get" aria-label="Permalink to &quot;列出模型 GET&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer &lt;你的 API Key&gt;&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>更易复制的写法：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer sk-你的专属Key&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果你本机装了 <code>jq</code>，也可以直接只看模型 ID：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer sk-你的专属Key&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;"> jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &#39;.data[].id&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样做的好处是不用在一大段 JSON 里来回找。<br> 第一次排查“这把 Key 到底看得到哪些模型”时，<code>jq</code> 这一种写法通常最省时间。</p><h2 id="响应里看什么" tabindex="-1">响应里看什么 <a class="header-anchor" href="#响应里看什么" aria-label="Permalink to &quot;响应里看什么&quot;">​</a></h2><p>重点看：</p><ul><li><code>id</code>：实际调用时要写的模型名</li><li><code>object</code>：通常是 <code>model</code></li><li>返回数量：当前 Key 能看到多少模型</li></ul><p>第一次排障时，<code>id</code> 是最重要的字段。<br> 客户端、脚本、CLI 最终真正需要填写的，都是这里返回的 <code>id</code>。</p><p>常见响应结构：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  &quot;object&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;list&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  &quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">      &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;从模型广场复制的实际模型名&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">      &quot;object&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;model&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>调用聊天、图像、音频等接口时，<code>model</code> 字段就填这里的 <code>id</code>。</p><p>也就是说，接口里返回的 <code>id</code> 才是你真正应该复制到脚本和客户端里的内容。</p><p>如果某个客户端内置了一堆旧模型名，也不要优先相信客户端下拉框。<br> 模型广场和 <code>/v1/models</code> 返回的结果，通常更接近当前实际可用状态。</p><h2 id="怎么选择模型" tabindex="-1">怎么选择模型 <a class="header-anchor" href="#怎么选择模型" aria-label="Permalink to &quot;怎么选择模型&quot;">​</a></h2><p>模型选择先看任务，再看成本和上下文长度。第一次接入时不要直接选择最贵或最重的模型，先用轻量模型确认 Key、分组和 Base URL 都正确。</p><table tabindex="0"><thead><tr><th>场景</th><th>选择思路</th><th>说明</th></tr></thead><tbody><tr><td>第一次测试</td><td>轻量聊天模型</td><td>成本低，适合验证链路</td></tr><tr><td>Claude Code / Codex 写代码</td><td>代码能力强、上下文较长的模型</td><td>更适合读文件、改代码、解释报错</td></tr><tr><td>Cherry Studio 日常聊天</td><td>响应快、价格低的聊天模型</td><td>适合问答、翻译、总结</td></tr><tr><td>长文档总结</td><td>长上下文模型</td><td>避免文档过长导致截断</td></tr><tr><td>批量脚本</td><td>低成本模型</td><td>配合额度上限使用</td></tr><tr><td>向量检索</td><td>Embedding 模型</td><td>不能用聊天模型替代</td></tr><tr><td>文档排序</td><td>Rerank 模型</td><td>用于检索结果二次排序</td></tr></tbody></table><p>模型广场里通常会显示模型名、分组、价格和可用状态。复制模型名时，连同日期、后缀和大小写一起复制。</p><p>如果你在客户端里看到“自动拉取模型列表”，本质上通常也是在做这件事：<br> 向当前 Base URL 发一遍 <code>GET /v1/models</code>，然后把 <code>data[].id</code> 填进下拉框。</p><h2 id="分组和模型的关系" tabindex="-1">分组和模型的关系 <a class="header-anchor" href="#分组和模型的关系" aria-label="Permalink to &quot;分组和模型的关系&quot;">​</a></h2><p>分组会影响你能看到和调用哪些模型。创建 Key 时选择的分组，应该和模型广场里目标模型可用的分组匹配。</p><p>这里最容易混淆的是三层：</p><ul><li><strong>模型广场</strong>：告诉你系统里有哪些模型</li><li><strong>Key 分组 / 模型权限</strong>：决定你这把 Key 能不能看到、能不能调用</li><li><strong>客户端里的 <code>model</code> 字段</strong>：决定你这一次请求到底要调哪一个</li></ul><p>常见判断方式：</p><ol><li>先在模型广场找到目标模型。</li><li>查看该模型支持的分组和价格。</li><li>创建 Key 时选择能使用该模型的分组。</li><li>在客户端里填写模型广场复制的完整模型名。</li><li>如果调用时报 <code>model not found</code>，回到令牌管理检查分组和模型权限。</li></ol><p>个人首次接入可以先选 <code>auto</code> 或默认分组。共享 Key 或批量任务再收紧到具体分组和具体模型。</p><h2 id="不同协议的模型列表" tabindex="-1">不同协议的模型列表 <a class="header-anchor" href="#不同协议的模型列表" aria-label="Permalink to &quot;不同协议的模型列表&quot;">​</a></h2><p>小蓝中转站 会根据请求头识别部分协议格式：</p><ul><li>OpenAI 兼容工具：请求 <code>/v1/models</code></li><li>Claude 兼容工具：带 <code>x-api-key</code> 和 <code>anthropic-version</code></li><li>Gemini 兼容工具：请求 <code>/v1beta/models</code> 或带 Gemini 相关鉴权参数</li></ul><p>普通用户和大多数桌面客户端只需要 <code>/v1/models</code>。</p><p>这里顺手记一个边界会更不容易混淆：</p><ul><li>你在 Cherry Studio、Alma、OpenAI SDK 里拉模型，通常看的就是 <code>/v1/models</code></li><li>你在 Claude Code、Gemini CLI 这类非 OpenAI 兼容工具里，模型获取和鉴权方式可能完全不是这一套</li></ul><p>所以“<code>/v1/models</code> 能拿到列表”只能证明 OpenAI 兼容链路正常，不能自动推出所有协议的 CLI 都已经配置完成。</p><h2 id="为什么有时接口返回的模型比模型广场少" tabindex="-1">为什么有时接口返回的模型比模型广场少 <a class="header-anchor" href="#为什么有时接口返回的模型比模型广场少" aria-label="Permalink to &quot;为什么有时接口返回的模型比模型广场少&quot;">​</a></h2><p>最常见的原因不是接口坏了，而是当前这把 Key 的可见范围更窄，例如：</p><ul><li>当前分组不包含目标模型</li><li>当前 Key 被收紧了模型权限</li><li>某个模型正在维护或暂时下线</li></ul><p>所以排障顺序通常是：</p><ol><li>先看模型广场有没有这个模型</li><li>再看当前分组是否能用</li><li>再看这把 Key 的模型权限是否放开</li><li>最后再回接口里重新拉一次列表</li></ol><p>如果你刚改过 Key 权限，桌面客户端或长会话工具可能还在沿用旧缓存。<br> 这时候不要只盯着客户端的旧下拉框，先重新拉一次 <code>/v1/models</code>，再决定是不是客户端本地缓存没刷新。</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>模型名不要手敲，直接复制</li><li>不同 Key 能看到的列表可能不同</li><li>价格直接去模型广场看更方便</li><li>模型广场下线或维护中的模型，不要继续写进脚本</li><li>先用轻量模型跑通，再切高阶模型</li><li>不确定时，先用 <code>/v1/models</code> 验证当前 Key 实际可见范围</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="模型广场有-接口里没有" tabindex="-1">模型广场有，接口里没有 <a class="header-anchor" href="#模型广场有-接口里没有" aria-label="Permalink to &quot;模型广场有，接口里没有&quot;">​</a></h3><p>通常是这把 Key 的权限组不包含该模型。回控制台检查令牌权限，或换一把权限更完整的 Key。</p><h3 id="接口里有-调用时报模型不存在" tabindex="-1">接口里有，调用时报模型不存在 <a class="header-anchor" href="#接口里有-调用时报模型不存在" aria-label="Permalink to &quot;接口里有，调用时报模型不存在&quot;">​</a></h3><p>先检查请求里的模型名是否完整复制。模型名大小写、日期后缀、连接符都要一致。</p><p>如果你用的是桌面客户端，还要再看一眼它保存的是不是旧模型。<br> 不少客户端第一次导入模型后会把模型列表缓存在本地，后台权限已经改过了，客户端还在继续用旧值。</p><h3 id="不知道选哪个模型" tabindex="-1">不知道选哪个模型 <a class="header-anchor" href="#不知道选哪个模型" aria-label="Permalink to &quot;不知道选哪个模型&quot;">​</a></h3><p>先按任务选：</p><ul><li>日常聊天：轻量模型</li><li>代码生成：Claude / GPT 系列强模型</li><li>长文总结：Gemini / 长上下文模型</li><li>向量检索：Embedding 模型</li><li>文档排序：Rerank 模型</li></ul><p>仍不确定时，先用轻量模型跑通，再按任务切换。</p><h3 id="客户端有-自动获取模型-按钮-还要不要手动拉接口" tabindex="-1">客户端有“自动获取模型”按钮，还要不要手动拉接口 <a class="header-anchor" href="#客户端有-自动获取模型-按钮-还要不要手动拉接口" aria-label="Permalink to &quot;客户端有“自动获取模型”按钮，还要不要手动拉接口&quot;">​</a></h3><p>一般不必重复做两遍。<br> 桌面客户端能正常自动获取时，优先用客户端内置按钮；只有在客户端拿不到模型、你又想确认是不是 Key 权限问题时，再手动请求 <code>/v1/models</code>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/api/chat">聊天</a></li><li><a href="/api/completions">补全</a></li><li><a href="/support/faq">常见问题</a></li></ul>`,65)])])}const u=a(t,[["render",n]]);export{k as __pageData,u as default};
